// Map EEA quality labels to our Portuguese DB values
const QUALITY = {
  '1 - Excellent'          : 'excelente',
  '2 - Good'               : 'boa',
  '3 - Good or Sufficient' : 'aceitavel',
  '4 - Poor'               : 'ma'
};

const results = $input.first().json.results ?? [];
console.log(`EEA returned ${results.length} PT records`);
if (results.length > 0) console.log('Sample:', JSON.stringify(results[0]));

const classified = results.filter(r => QUALITY[r.quality]);
console.log(`${classified.length} records with a known classification`);

if (classified.length === 0) throw new Error('No classified beaches — check EEA query or field names');

// Build a bulk INSERT ... JOIN ... ON CONFLICT using a VALUES table
// Season year is extracted from the season field (integer in EEA data)
const values = classified
  .map(r => `('${r.bathingWaterIdentifier}', '${QUALITY[r.quality]}', '${r.season ?? 2024}-07-01')`)
  .join(',\n');

const sql = `
INSERT INTO qualidade_agua (praia_id, classificacao, data_analise, updated_at)
SELECT p.id, v.classificacao, v.data_analise::date, NOW()
FROM (
  VALUES ${values}
) AS v(bathingWaterIdentifier, classificacao, data_analise)
JOIN praias p ON p.codigo_agua_balnear = v.bathingWaterIdentifier
ON CONFLICT (praia_id) DO UPDATE SET
  classificacao = EXCLUDED.classificacao,
  data_analise  = EXCLUDED.data_analise,
  updated_at    = EXCLUDED.updated_at
`;

return [{ json: { sql, total: classified.length } }];
